// ─── Helpers ──────────────────────────────────────────────────────────────────

export function settlementsByAnchor(anchor: AnchorId): Settlement[] {
  return SETTLEMENT_DATABASE.filter((s) => s.anchors.includes(anchor));
}

export function settlementsByType(type: PlaceType): Settlement[] {
  return SETTLEMENT_DATABASE.filter((s) => s.placeType === type);
}

export function settlementsByClassification(cls: SettlementClassification): Settlement[] {
  return SETTLEMENT_DATABASE.filter((s) => s.classification === cls);
}

export function withKnownPopulation(): Settlement[] {
  return SETTLEMENT_DATABASE.filter((s) => s.population !== null);
}
